;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@roadguide n="Sapphire City" e=Orchard

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@notice text="Foster family"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true

@enterhouse img=interior_01
[texton]
There is no one in the room.[k]
[textoff]
@exithouse

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

@wait time=500 cond='WAY != "s"'
@walk turn=s cond='WAY != "s"'
@wait time=500
@walk move=n
@wait time=500
@eval exp='game.curChara = game.chara[f.kidnappedElfID]'
@jump storage="heroine02b.scn" target=*theo_08

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] true

; 救出が成功するルート
@call target=*_rescue_elf
@eval exp='f.wayOfRescuingElf = "a"' cond='f.wayOfRescuingElf === void'
@walk turn=s cond='WAY != "s"'
@walk move=s
@walk move=s cond='game.party.curY > 7'

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] true

; 救出が失敗するルート
@call target=*_rescue_elf
@eval exp='f.wayOfRescuingElf = "b"' cond='f.wayOfRescuingElf === void'
@walk turn=n cond='WAY != "n"'
@walk move=n

[eventoff]
;-------------------------------------------------------------------------------
*_rescue_elf

@eval exp='game.curChara = game.chara[f.kidnappedElfID]'
[if exp='f.wayOfRescuingElf === void']
	[texton]
	[テオ]「Okay, almost there!」[k]
	The mansion where [クレア] is being held captive must be somewhere in the Forest of Power.[k]
	[textoff]
[else]
	[texton]
	There's no turning back now. We must rescue [クレア] as soon as possible.
	 [k]
	[textoff]
[endif]
@return
;-------------------------------------------------------------------------------
